using namespace std;

int main(){
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int N, k;
    cin &gt;&gt; N &gt;&gt; k;
    vector&lt;int&gt; V(N+1), B(N+1);
    for (int i = 1; i &lt;= N; i++) cin &gt;&gt; V[i];
    for (int i = 1; i &lt;= N; i++) cin &gt;&gt; B[i];

    vector&lt;vector&lt;int&gt;&gt; dp(N+2, vector&lt;int&gt;(N+2, 0));

    for (int i = N; i &gt;= 1; i--){
        for (int j = i; j &lt;= N; j++){
            dp[i][j] = dp[i+1][j]; // Skip bracket at i
            if(B[i] &lt;= k){
                for (int m = i+1; m &lt;= j; m++){
                    if(B[m] == B[i] + k){
                        int candidate = V[i] + V[m];
                        if(i+1 &lt;= m-1)
                            candidate += dp[i+1][m-1];
                        if(m+1 &lt;= j)
                            candidate += dp[m+1][j];
                        dp[i][j] = max(dp[i][j], candidate);
                    }
                }
            }
        }
    }
    cout &lt;&lt; dp[1][N] &lt;&lt; "\n";
    return 0;
}
